// OJ-Call-Completion-Reminders (OJ-FUNNEL B1, 2026-07-19)
// Paid buyers who have not completed their Annie assessment call get a day-2 and a day-5
// reminder. Idempotent via outcome_attribution rows (call_reminder_1 / call_reminder_2 keyed
// by stripe session_id). TEST_MODE=true routes every send to the test inbox; flip to false
// after the first watched live cycle (browser-automation 5-row rule analog).
const OJ_URL='https://wwacjhkpuaiijbkqnhsi.supabase.co';
const OJ_KEY='eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Ind3YWNqaGtwdWFpaWpia3FuaHNpIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3ODgwODQyNSwiZXhwIjoyMDk0Mzg0NDI1fQ.I92OcFBQ9lxs4hFH3Q_rWYup2bULHuL3a2rqeEb1xf0';
const RESEND_KEY='re_xRcPgRZQ_K4amwq6HnzHsYMfsMWPW23nB';
const TEST_MODE=true;
const TEST_EMAIL='adrientharrison@gmail.com';
const H={apikey:OJ_KEY,Authorization:'Bearer '+OJ_KEY,'Content-Type':'application/json'};
async function get(p){return await this.helpers.httpRequest({method:'GET',url:OJ_URL+'/rest/v1/'+p,headers:H,json:true});}
async function post(p,body){return await this.helpers.httpRequest({method:'POST',url:OJ_URL+'/rest/v1/'+p,headers:{...H,Prefer:'return=minimal'},body,json:true});}

const now=Date.now();
const pays=await get.call(this,'outcome_attribution?select=id,prospect_id,notes,created_at&outcome_type=eq.payment_settled&order=created_at.desc&limit=50');
const out=[];
for(const pay of pays){
  let notes={}; try{notes=JSON.parse(pay.notes||'{}');}catch(e){}
  const email=(notes.customer_email||'').toLowerCase();
  const sid=notes.session_id||null;
  if(!email||!sid) continue;
  const ageDays=(now-Date.parse(pay.created_at))/86400000;
  if(ageDays<2||ageDays>30) continue;
  // completed? assessment exists for prospect, or call_completed attribution for this session
  if(pay.prospect_id){
    const a=await get.call(this,'assessments?select=id&prospect_id=eq.'+pay.prospect_id+'&limit=1');
    if(a.length) continue;
  }
  const done=await get.call(this,'outcome_attribution?select=id&outcome_type=eq.assessment_call_completed&notes=like.*'+encodeURIComponent(sid)+'*&limit=1');
  if(done.length) continue;
  const stage=ageDays>=5?'call_reminder_2':'call_reminder_1';
  const sent=await get.call(this,'outcome_attribution?select=id&outcome_type=eq.'+stage+'&notes=like.*'+encodeURIComponent(sid)+'*&limit=1');
  if(sent.length) continue;
  const to=TEST_MODE?TEST_EMAIL:email;
  const second=stage==='call_reminder_2';
  const subject=second?'Last reminder: your paid AI assessment call is still waiting':'Your AI assessment call is the next step';
  const html='<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;color:#1a1a2e;font-size:15px;line-height:1.6">'
    +'<p>Hi,</p>'
    +'<p>You already paid for your OpsJuice AI assessment, and the assessment call is the one step left before we can write your report.</p>'
    +'<p>Call Annie, our AI interviewer, at <strong>(602) 600-0351</strong> whenever it suits you. The call takes about 15 minutes, and your written report arrives within 48 hours after it.</p>'
    +(second?'<p>If a scheduled time works better, reply to this email with two time windows and we will set it up.</p>':'<p>Prefer a scheduled time? Just reply to this email.</p>')
    +'<p>Adrien<br>OpsJuice</p>'
    +'<p style="font-size:11px;color:#888">Echo Collective LLC, 8 East 96th Street, New York, NY 10128. Reply STOP to opt out.</p></div>';
  await this.helpers.httpRequest({method:'POST',url:'https://api.resend.com/emails',
    headers:{Authorization:'Bearer '+RESEND_KEY,'Content-Type':'application/json'},
    body:{from:'OpsJuice <info@opsjuice.com>',to:[to],subject,html},json:true});
  await post.call(this,'outcome_attribution',{company_id:'opsjuice',outcome_type:stage,prospect_id:pay.prospect_id,
    notes:JSON.stringify({session_id:sid,to,test_mode:TEST_MODE})});
  out.push({sid,stage,to});
}
return [{json:{sent:out.length,detail:out}}];
